INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-05110', 'social-worker', 'social-worker-moex-107-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「理想是有意義、有價值，可以讓人懷著熱情，興高采烈去做的事；它可以讓人不 計得失，甚至犧牲生命也覺得值得。現實是欠缺意義和價值的事，它引不起人的熱 情，讓人做起來不甘不願。但是，只有少數人敢於犧牲一部分的現實去換取理想， 大多數人卻再怎麼厭惡都得屈服於現實，再怎麼渴望理想都可以輕易拋棄它。關鍵 在於你有沒有嘗過理想的滋味，以及培養出追求理想的能力。」 下列選項，何者最符合本文意旨？', '["為追求理想，只能暫時與現實妥協", "理想誠然可貴，但也應要兼顧現實", "理想與現實其實並不一定衝突矛盾", "理想更可貴，但多數人屈從於現實"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "05a12fd5dfac", "answer_pdf_sha1": "56bbb7e6baef", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05111', 'social-worker', 'social-worker-moex-107-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「很少有食物像月餅，既浪漫美麗又俗儈不堪，它不僅是應節食品，更是人際儀式 的祭品，餡內包藏著複雜的社交權力關係。一般人買年糕、湯圓、粽子和紅龜粿等 過節食品，總是帶回家吃，但月餅卻買來送人或是被送，甚或多次轉送，形成一種 流動的再分配，而不管最後失蹤或留下，月餅都因而衍生出複雜的交換價值。」下 列選項最符合文意的是：', '["月餅的美好滋味，遠勝年糕湯圓等傳統過節食品", "食物背後牽涉人情世故與文化意涵，象徵意義豐富", "只重物質表象忽略情意，恐流於庸俗，時人應引以為誡", "應節食品具有特殊象徵意義，不應多次轉送，以免扭曲本意"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "05a12fd5dfac", "answer_pdf_sha1": "56bbb7e6baef", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05112', 'social-worker', 'social-worker-moex-107-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '莊子將死，弟子欲厚葬之。莊子曰：「吾以天地為棺槨，以日月為連璧，星辰為珠 璣，萬物為齎送。吾葬具豈不備邪？何以加此！」弟子曰：「吾恐烏鳶之食夫子也。」 莊子曰：「在上為烏鳶食，在下為螻蟻食，奪彼與此，何其偏也！」（《莊子．列 禦寇》） 下列關於文意的敘述，最貼近上文內容的是：', '["莊子對死看得開，死亡即是回歸自然", "儘管不希望厚葬，但仍希望有陪葬品", "害怕死亡的人，才會擔心屍體被吃食", "與其被螻蟻食，不如為烏鳶食較灑脫"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "05a12fd5dfac", "answer_pdf_sha1": "56bbb7e6baef", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05113', 'social-worker', 'social-worker-moex-107-7c9828ae', 'sub-social-worker-02', NULL, 'essay', '隨著社會日益多元化，「包容」（inclusion）也成為社會工作的重要價
值。請說明「包容」的意義為何？並以家庭社會工作為例，申論社工專
業人員應以何種基本態度面對現代家庭的多樣化？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "ef1c39f01ce8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會工作", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": "一", "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05114', 'social-worker', 'social-worker-moex-107-7c9828ae', 'sub-social-worker-02', NULL, 'essay', '脫貧與自立生活準備是兒少轉銜到成年階段的重要任務，請說明目前臺
灣有那些類型的方案協助兒少脫貧與自立生活準備？並舉任何一個你
所了解的方案，申論脫貧與自立生活的關鍵影響因素為何？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "ef1c39f01ce8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會工作", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05115', 'social-worker', 'social-worker-moex-107-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作理論所涵蓋或觸及的問題範疇而言，可以分為鉅視層次、居間層次與微觀層次。請問下 列那一個理論與其他理論所屬的層次不同？', '["基變理論", "精神分析理論", "認知行為理論", "心理暨社會派"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "ef1c39f01ce8", "answer_pdf_sha1": "88fc76ce2539", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05116', 'social-worker', 'social-worker-moex-107-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '同理的溝通是個案會談時常用的技巧之一。有關同理的溝通之敘述，下列何者正確？', '["同理的溝通主要是要抓取案主當下外顯的感受，不需要發現感覺與行為的意義", "依據黑普渥斯（Hepworth）等人的觀點，同理的回應可以分為低層次→中度→高層次三個等級", "低層次的同理回應是指回應者針對內在的訊息進行回應", "同理與同情的差異在於同理即使境遇不同，也能了解他人的感受與處境"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "ef1c39f01ce8", "answer_pdf_sha1": "88fc76ce2539", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05117', 'social-worker', 'social-worker-moex-107-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列何者不是增強權能的觀點？', '["個人之所以無法實現自己，主要是源於環境加諸本身的壓迫與限制", "個人問題的發生是歸因於個人的缺陷", "增強權能取向的實施是要致力於改革壓迫案主的環境或結構", "探索個人問題成因，以了解及欣賞個人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "ef1c39f01ce8", "answer_pdf_sha1": "88fc76ce2539", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05118', 'social-worker', 'social-worker-moex-107-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列有關社會工作理論之描述，何者錯誤？', '["認知行為理論認為案主現在思考模式和生活型態才是影響問題的主要原因", "精神分析觀點認為個人問題是源自於內在的精神衝突與防衛機轉失敗", "系統理論著重於個人層面的介入以及強調自我理性的部分", "社會網絡干預模型強調運用網絡中的人們，協助案主解決問題"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "ef1c39f01ce8", "answer_pdf_sha1": "88fc76ce2539", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05119', 'social-worker', 'social-worker-moex-107-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '依據社會工作師法規定，社會工作紀錄保存不得少於幾年？', '["5年", "3年", "7年", "1年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "ef1c39f01ce8", "answer_pdf_sha1": "88fc76ce2539", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
